#define THREADS 256
#define WIDTH 16  
#define HEIGHT 16 
#define ETA 0.3f       
#define MOMENTUM 0.3f  

#define WM(i, j)   weight_matrix[(j) + (i) * WIDTH]

__global__ void 
bpnn_layerforward_cuda(float *input_cuda,
	                  float *output_hidden_cuda,
					  float *input_hidden_cuda,
					  float *hidden_partial_sum,
					  int in,
					  int hid) 
{
   extern __shared__ float input_node[HEIGHT];
   extern __shared__ float weight_matrix[HEIGHT * WIDTH];

   int by = blockIdx.y;
   int tx = threadIdx.x;
   int ty = threadIdx.y;

   int index =  ( hid + 1 ) * HEIGHT * by + ( hid + 1 ) * ty + tx + 1 + ( hid + 1 ) ;  

   int index_in = HEIGHT * by + ty + 1;

	if ( tx == 0 )
		input_node[ty] = input_cuda[index_in] ;
	__syncthreads();

	weight_matrix[ty * WIDTH + tx] =  input_hidden_cuda[index];
	__syncthreads();

	weight_matrix[ty * WIDTH + tx]= weight_matrix[ty * WIDTH + tx] * input_node[ty];
	__syncthreads();

	for ( int i = 1 ; i <= HEIGHT ; i=i*2){

      int power_two = i; 

	    if( ty % power_two == 0 )
		  weight_matrix[ty * WIDTH + tx]= weight_matrix[ty * WIDTH + tx] + weight_matrix[(ty + power_two/2)* WIDTH + tx];

		__syncthreads();
    }

    input_hidden_cuda[index] =  weight_matrix[ty * WIDTH + tx];

	__syncthreads();

    if ( tx == 0 ) {
	  hidden_partial_sum[by * hid + ty] = weight_matrix[tx* WIDTH + ty];
    }
}

__global__ void bpnn_adjust_weights_cuda( float * delta,   
										 int hid,         
										float * ly,      
										 int in,          
										float * w,       
										float * oldw)  									
{

   int by = blockIdx.y;
   int tx = threadIdx.x;
   int ty = threadIdx.y;

   int index =  ( hid + 1 ) * HEIGHT * by + ( hid + 1 ) * ty + tx + 1 + ( hid + 1 ) ;  
   int index_y = HEIGHT * by + ty + 1;
   int index_x = tx + 1;

   w[index] += ((ETA * delta[index_x] * ly[index_y]) + (MOMENTUM * oldw[index]));
   oldw[index] = ((ETA * delta[index_x] * ly[index_y]) + (MOMENTUM * oldw[index]));

   __syncthreads();

   if (ty == 0 && by ==0){
	w[index_x] += ((ETA * delta[index_x]) + (MOMENTUM * oldw[index_x]));
	oldw[index_x] = ((ETA * delta[index_x]) + (MOMENTUM * oldw[index_x]));
   }
}

