#include <stdlib.h>
#include <stdio.h>
#include <string.h>
#include <math.h>
#include <sys/time.h>
#include "backprop.h"

#ifdef TIMING
    #include "timing.h"
#endif

#ifdef TIMING
struct timeval tv;
struct timeval tv_total_start, tv_total_end;
struct timeval tv_init_end;
struct timeval tv_h2d_start, tv_h2d_end;
struct timeval tv_d2h_start, tv_d2h_end;
struct timeval tv_kernel_start, tv_kernel_end;
struct timeval tv_mem_alloc_start, tv_mem_alloc_end;
struct timeval tv_close_start, tv_close_end;
float init_time = 0, mem_alloc_time = 0, h2d_time = 0, kernel_time = 0,
      d2h_time = 0, close_time = 0, total_time = 0;
#endif

double gettime() {
  struct timeval t;
  gettimeofday(&t,NULL);
  return t.tv_sec+t.tv_usec*1e-6;
}

unsigned int num_threads = 0;
unsigned int num_blocks = 0;

int
main( int argc, char** argv)
{
	setup(argc, argv);
}

int bpnn_train_kernel(BPNN *net, float *eo, float *eh)
{
	int in, hid, out;
	float out_err, hid_err;

	in = net->input_n;
	hid = net->hidden_n;
	out = net->output_n;

#ifdef  TIMING
    gettimeofday(&tv_total_start, NULL);
#endif

#ifdef  TIMING
    gettimeofday(&tv_init_end, NULL);
	tvsub(&tv_init_end, &tv_total_start, &tv);
	init_time = tv.tv_sec * 1000.0 + (float) tv.tv_usec / 1000.0;
#endif

	float *input_weights_one_dim;
    float *input_weights_prev_one_dim;
	float * partial_sum;
	float sum;
	float num_blocks = in / BLOCK_SIZE;

	input_weights_one_dim = (float *) malloc((in + 1)* (hid + 1) * sizeof(float));
	input_weights_prev_one_dim = (float *) malloc((in + 1)* (hid + 1) * sizeof(float));
	partial_sum = (float *) malloc(num_blocks * WIDTH * sizeof(float));

	dim3 global_work(BLOCK_SIZE, BLOCK_SIZE * num_blocks, 1);
	dim3 local_work(BLOCK_SIZE, BLOCK_SIZE, 1);

	int m = 0;
	for (int k = 0; k <= in; k++) {
		for (int j = 0; j <= hid; j++) {
		input_weights_one_dim[m] = net->input_weights[k][j];
		input_weights_prev_one_dim[m] = net-> input_prev_weights[k][j];
	    m++;
		}
	}

	float *input_hidden_cuda;
    float *input_cuda;
	float *output_hidden_cuda;
	float *hidden_partial_sum;
	float *hidden_delta_cuda;
	float *input_prev_weights_cuda;

#ifdef  TIMING
    gettimeofday(&tv_mem_alloc_start, NULL);
#endif
	cudaMalloc(&input_cuda, (in + 1) * sizeof(float));
	cudaMalloc(&input_hidden_cuda, (in + 1) * (hid + 1) * sizeof(float));
	cudaMalloc(&output_hidden_cuda, (hid + 1) * sizeof(float));
	cudaMalloc(&hidden_partial_sum, num_blocks * WIDTH * sizeof(float));
	cudaMalloc(&hidden_delta_cuda, (hid + 1) * sizeof(float));
	cudaMalloc(&input_prev_weights_cuda, (in + 1) * (hid + 1) * sizeof(float));
#ifdef  TIMING
    gettimeofday(&tv_mem_alloc_end, NULL);
    tvsub(&tv_mem_alloc_end, &tv_mem_alloc_start, &tv);
    mem_alloc_time = tv.tv_sec * 1000.0 + (float) tv.tv_usec / 1000.0;
#endif

	printf("Performing GPU computation\n");

	cudaEvent_t event;
	cudaEvent_t write_event[3];
	cudaEventCreate(&event);
	cudaEventCreate(&write_event[0]);
	cudaEventCreate(&write_event[1]);

	cudaMemcpy(input_cuda, net->input_units, (in + 1) * sizeof(float), cudaMemcpyHostToDevice);
	cudaMemcpy(input_hidden_cuda, input_weights_one_dim, (in + 1) * (hid + 1) * sizeof(float), cudaMemcpyHostToDevice);
#ifdef TIMING
    h2d_time += probe_event_time(write_event[0]);
    h2d_time += probe_event_time(write_event[1]);
#endif

	int shared_mem_size = HEIGHT * sizeof(float) + HEIGHT * WIDTH * sizeof(float);
	bpnn_layerforward_cuda<<<global_work, local_work, shared_mem_size>>>(input_cuda, output_hidden_cuda, input_hidden_cuda, hidden_partial_sum, in, hid);

	cudaMemcpy(partial_sum, hidden_partial_sum, num_blocks * WIDTH * sizeof(float), cudaMemcpyDeviceToHost);
#ifdef TIMING
    d2h_time += probe_event_time(event);
#endif

	for (int j = 1; j <= hid; j++) {
		sum = 0.0;
		for (int k = 0; k < num_blocks; k++) {
		sum += partial_sum[k * hid + j-1] ;
    }
		sum += net->input_weights[0][j];
		net-> hidden_units[j] = float(1.0 / (1.0 + exp(-sum)));
	}

	bpnn_layerforward(net->hidden_units, net->output_units, net->hidden_weights, hid, out);
	bpnn_output_error(net->output_delta, net->target, net->output_units, out, &out_err);
	bpnn_hidden_error(net->hidden_delta, hid, net->output_delta, out, net->hidden_weights, net->hidden_units, &hid_err);
	bpnn_adjust_weights(net->output_delta, out, net->hidden_units, hid, net->hidden_weights, net->hidden_prev_weights);

	cudaMemcpy(hidden_delta_cuda, net->hidden_delta, (hid + 1) * sizeof(float), cudaMemcpyHostToDevice);
	cudaMemcpy(input_prev_weights_cuda, input_weights_prev_one_dim, (in + 1) * (hid + 1) * sizeof(float), cudaMemcpyHostToDevice);
	cudaMemcpy(input_hidden_cuda, input_weights_one_dim, (in + 1) * (hid + 1) * sizeof(float), cudaMemcpyHostToDevice);
#ifdef TIMING
    h2d_time += probe_event_time(write_event[0]);
    h2d_time += probe_event_time(write_event[1]);
    h2d_time += probe_event_time(write_event[2]);
#endif

	bpnn_adjust_weights_cuda<<<global_work, local_work>>>(hidden_delta_cuda, hid, input_cuda, in, input_hidden_cuda, input_prev_weights_cuda);

	cudaMemcpy(net->input_units, input_cuda, (in + 1) * sizeof(float), cudaMemcpyDeviceToHost);
	cudaMemcpy(input_weights_one_dim, input_hidden_cuda, (in + 1) * (hid + 1) * sizeof(float), cudaMemcpyDeviceToHost);
#ifdef TIMING
    d2h_time += probe_event_time(event);
#endif

#ifdef  TIMING
	gettimeofday(&tv_close_start, NULL);
#endif

	cudaFree(input_cuda);
	cudaFree(output_hidden_cuda);
	cudaFree(input_hidden_cuda);
	cudaFree(hidden_partial_sum);
	cudaFree(input_prev_weights_cuda);

	free(input_weights_prev_one_dim);
	free(partial_sum);
	free(input_weights_one_dim);

#ifdef  TIMING
	gettimeofday(&tv_close_end, NULL);
	tvsub(&tv_close_end, &tv_close_start, &tv);
	close_time = tv.tv_sec * 1000.0 + (float) tv.tv_usec / 1000.0;
	tvsub(&tv_close_end, &tv_total_start, &tv);
	total_time = tv.tv_sec * 1000.0 + (float) tv.tv_usec / 1000.0;

	printf("Init: %f\n", init_time);
	printf("MemAlloc: %f\n", mem_alloc_time);
	printf("HtoD: %f\n", h2d_time);
	printf("Exec: %f\n", kernel_time);
	printf("DtoH: %f\n", d2h_time);
	printf("Close: %f\n", close_time);
	printf("Total: %f\n", total_time);
#endif
}
